LL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),(2328,6,12,'Canaanite scarab of the early Palestinian series, glazed steatite, no remains of glaze. \nBack: plain, decorated with a long-stem lotus flower and two spirals\nHead: D5\nSide: e10\nBase design: 7A2 - continuous scroll border, oblong scrolls. The bottom part of the base is broken.\nContinuous border of oblong scrolls enclosing a Horus falcon wearing the Red Crown of Lower Egypt as a central motif.',NULL,NULL,2,2,NULL,NULL,1,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),(2329,6,12,'Canaanite scarab of the early Palestinian series, glazed steatite, no remains of glaze. Two fragments comprising half a scarab preserved. Metal residue inside perforation.\nBack: lined, decorated with spirals\nHead: A5\nSide: d5\nBase design: 3C - formulae',NULL,NULL,2,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),(2330,4,1,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),(2331,4,1,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),(2332,4,1,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),(2333,4,2,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),(2334,1,1,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),(2335,4,1,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),(2336,4,1,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),(2338,1,1,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),(2339,1,1,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),(2340,6,1,'Short barrel bead, flint or carnelian',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),(2341,6,12,'Middle Kingdom Egyptian scarab from Tell el-Dab\'a workshop, glazed steatite, no remains of glaze. Two fragments comprising the bottom and one side of the scarab preserved. Metal residue inside hole.\nBack: lined\nHead: B, typical of the early scarab workshop at Tell el-Dab\'a\nSide: e9',NULL,NULL,2,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),(2342,1,1,'obsidian',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),(2343,1,1,'Possibly natural?',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
